    25→  private async runMaproomScan(worktreePath: string): Promise<void> {
    26→    try {
    27→      // Try to find the maproom binary using the same logic as maproom.ts
    28→      const execName = process.platform === 'win32' ? 'crewchief-maproom.exe' : 'crewchief-maproom'
    29→      const arch = process.arch === 'x64' ? 'x64' : process.arch === 'arm64' ? 'arm64' : process.arch
    30→      const platform = `${process.platform}-${arch}`
    31→
    32→      let maproomBin: string | null = null
    33→
    34→      // Check environment variable first
    35→      if (process.env.CREWCHIEF_MAPROOM_BIN && fs.existsSync(process.env.CREWCHIEF_MAPROOM_BIN)) {
    36→        maproomBin = process.env.CREWCHIEF_MAPROOM_BIN
    37→      }
    38→
    39→      // Try packaged binary locations
    40→      if (!maproomBin) {
    41→        const __dirname = path.dirname(fileURLToPath(import.meta.url))
    42→        const possiblePaths = [
    43→          path.join(__dirname, '..', 'bin', platform, execName),
    44→          path.join(__dirname, '..', 'bin', execName),
    45→          path.join(__dirname, '..', '..', 'maproom-mcp', 'bin', platform, execName),
    46→        ]
    47→        for (const p of possiblePaths) {
    48→          if (fs.existsSync(p)) {
    49→            maproomBin = p
    50→            break
    51→          }
    52→        }
    53→      }
    54→
    55→      // Try global installation
    56→      if (!maproomBin) {
    57→        const which = spawnSync('bash', ['-lc', 'command -v crewchief-maproom'])
    58→        if (which.status === 0) {
    59→          maproomBin = 'crewchief-maproom'
    60→        }
    61→      }
    62→
    63→      if (!maproomBin) {
    64→        console.log('⚠️  Maproom binary not found, skipping indexing for new worktree')
    65→        return
    66→      }
    67→
    68→      console.log('🔍 Running maproom scan for new worktree...')
    69→
    70→      // Run maproom scan with automatic detection (it will detect repo, worktree, and commit from the worktree path)
    71→      const result = spawnSync(maproomBin, ['scan'], {
    72→        cwd: worktreePath,
    73→        encoding: 'utf8',
    74→        stdio: ['pipe', 'pipe', 'pipe'],
    75→      })
    76→
    77→      if (result.status === 0) {
    78→        // Parse output to show summary
    79→        const output = result.stdout
    80→        if (output.includes('files processed') || output.includes('chunks created')) {
    81→          console.log('✅ Maproom indexing completed successfully')
    82→        } else {
    83→          console.log('✅ Maproom scan completed')
    84→        }
    85→      } else {
    86→        const errorMsg = result.stderr || result.stdout || 'Unknown error'
    87→        console.warn(`⚠️  Maproom scan failed: ${errorMsg.split('\n')[0]}`)
    88→      }
    89→    } catch (error) {
    90→      console.warn('⚠️  Failed to run maproom scan:', error instanceof Error ? error.message : error)
    91→    }
    92→  }
