   174→  async pruneWorktrees(opts?: { mode?: 'stale' | 'all'; keepDir?: boolean }): Promise<void> {
   175→    if (!opts || opts.mode === 'stale') {
   176→      await this.git.raw(['worktree', 'prune'])
   177→      return
   178→    }
   179→    if (opts.mode === 'all') {
   180→      const list = await this.listWorktrees()
   181→      // Use real paths so symlinks do not bypass the protection
   182→      const cwdReal = safeRealpath(this.cwd)
   183→      for (const item of list) {
   184→        const p = path.resolve(item.path)
   185→        const pReal = safeRealpath(p)
   186→        // Skip if current working directory is the same as, or inside, this worktree
   187→        const rel = path.relative(pReal, cwdReal)
   188→        const isCwdInside = rel === '' || (!rel.startsWith('..') && !path.isAbsolute(rel))
   189→        if (isCwdInside) continue // never remove current working tree
   190→        try {
   191→          // Force remove to handle unmerged/untracked files in the worktree
   192→          await this.git.raw(['worktree', 'remove', '--force', p])
   193→          // Delete the directory unless --keep-dir was specified
   194→          if (!opts.keepDir) {
   195→            removeDirSync(p)
   196→          }
   197→        } catch {
   198→          // ignore failures, continue best-effort
   199→        }
   200→      }
   201→    }
   202→  }
   203→
   204→  async removeWorktree(worktreePath: string): Promise<void> {
   205→    // Guard against deleting the current worktree (or its ancestor) even if asked
   206→    const targetPath = path.resolve(worktreePath)
   207→    const targetReal = safeRealpath(targetPath)
   208→    const cwdReal = safeRealpath(this.cwd)
   209→    const rel = path.relative(targetReal, cwdReal)
   210→    const isCwdInsideTarget = rel === '' || (!rel.startsWith('..') && !path.isAbsolute(rel))
   211→    if (isCwdInsideTarget) {
   212→      throw new Error('Refusing to remove the current worktree. Change directories and try again.')
   213→    }
   214→    await this.git.raw(['worktree', 'remove', '--force', targetPath])
   215→  }
   216→}
   217→
   218→function safeRealpath(p: string): string {
   219→  try {
   220→    return fs.realpathSync(p)
   221→  } catch {
   222→    return path.resolve(p)
   223→  }
   224→}
