   226→// Deterministic branch naming per spec: derive from agent id, optional task, and timestamp
   227→export function buildDeterministicBranchName(params: {
   228→  agentTypeId: string
   229→  taskDescription?: string
   230→  now?: Date
   231→}): string {
   232→  const safeId = slugify(params.agentTypeId)
   233→  const taskPart = params.taskDescription ? '-' + slugify(params.taskDescription).slice(0, 32) : ''
   234→  const d = params.now ?? new Date()
   235→  const ts =
   236→    d.getUTCFullYear().toString() +
   237→    pad2(d.getUTCMonth() + 1) +
   238→    pad2(d.getUTCDate()) +
   239→    pad2(d.getUTCHours()) +
   240→    pad2(d.getUTCMinutes()) +
   241→    pad2(d.getUTCSeconds())
   242→  return `cc-${safeId}${taskPart}-${ts}`
   243→}
   244→
   245→function pad2(n: number): string {
   246→  return n < 10 ? `0${n}` : `${n}`
   247→}
   248→
   249→function slugify(input: string): string {
   250→  return input
   251→    .toLowerCase()
   252→    .replace(/[^a-z0-9]+/g, '-')
   253→    .replace(/^-+|-+$/g, '')
   254→    .replace(/-{2,}/g, '-')
   255→}
